contract SecureBank {
    mapping(address => uint256) public balances;

    function withdraw(uint256 _amount) public {
        // 1. CHECKS - Validate all conditions first
        require(_amount > 0, "Amount must be positive");
        require(balances[msg.sender] >= _amount, "Insufficient balance");
        require(address(this).balance >= _amount, "Insufficient contract balance");

        // 2. EFFECTS - Update state before external calls
        balances[msg.sender] -= _amount;

        // 3. INTERACTIONS - External calls last
        (bool success, ) = msg.sender.call{value: _amount}("");
        require(success, "Transfer failed");

        emit Withdrawal(msg.sender, _amount);
    }

    // More complex example with multiple state changes
    function transferFrom(address _from, address _to, uint256 _amount) public {
        // CHECKS
        require(_from != address(0) && _to != address(0), "Invalid address");
        require(_amount > 0, "Amount must be positive");
        require(balances[_from] >= _amount, "Insufficient balance");
        require(msg.sender == _from || allowances[_from][msg.sender] >= _amount, "Not authorized");

        // EFFECTS - All state changes
        balances[_from] -= _amount;
        balances[_to] += _amount;
        if (msg.sender != _from) {
            allowances[_from][msg.sender] -= _amount;
        }

        // INTERACTIONS - External call to notify recipient
        if (_isContract(_to)) {
            try ITokenReceiver(_to).onTokenReceived(_from, _amount) returns (bytes4 response) {
                require(response == ITokenReceiver.onTokenReceived.selector, "Invalid response");
            } catch {
                revert("Receiver rejected tokens");
            }
        }

        emit Transfer(_from, _to, _amount);
    }

    function _isContract(address _addr) private view returns (bool) {
        uint256 size;
        assembly { size := extcodesize(_addr) }
        return size > 0;
    }
}

