import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SecureDeFiVault
 * @notice Demonstrates proper use of ReentrancyGuard in a DeFi protocol
 * @dev Combines ReentrancyGuard with Checks-Effects-Interactions pattern
 */
contract SecureDeFiVault is ReentrancyGuard, Ownable {
    mapping(address => uint256) public deposits;
    mapping(address => uint256) public shares;
    uint256 public totalShares;
    uint256 public totalDeposits;

    event Deposited(address indexed user, uint256 amount, uint256 shares);
    event Withdrawn(address indexed user, uint256 amount, uint256 shares);
    event RewardsClaimed(address indexed user, uint256 amount);

    /**
     * @notice Deposit ETH and receive vault shares
     * @dev nonReentrant modifier prevents reentrancy attacks
     */
    function deposit() public payable nonReentrant {
        require(msg.value > 0, "Deposit amount must be positive");

        // Calculate shares based on current vault ratio
        uint256 sharesToMint;
        if (totalShares == 0) {
            sharesToMint = msg.value;
        } else {
            sharesToMint = (msg.value * totalShares) / totalDeposits;
        }

        // Effects - Update state
        deposits[msg.sender] += msg.value;
        shares[msg.sender] += sharesToMint;
        totalShares += sharesToMint;
        totalDeposits += msg.value;

        emit Deposited(msg.sender, msg.value, sharesToMint);
    }

    /**
     * @notice Withdraw ETH by burning shares
     * @param _shares Number of shares to burn
     * @dev nonReentrant protects against reentrancy during ETH transfer
     */
    function withdraw(uint256 _shares) public nonReentrant {
        require(_shares > 0, "Shares must be positive");
        require(shares[msg.sender] >= _shares, "Insufficient shares");

        // Calculate withdrawal amount
        uint256 withdrawAmount = (_shares * totalDeposits) / totalShares;
        require(withdrawAmount > 0, "Withdrawal amount must be positive");
        require(address(this).balance >= withdrawAmount, "Insufficient contract balance");

        // Effects - Update state BEFORE external call
        shares[msg.sender] -= _shares;
        deposits[msg.sender] -= withdrawAmount;
        totalShares -= _shares;
        totalDeposits -= withdrawAmount;

        // Interactions - External call protected by nonReentrant
        (bool success, ) = msg.sender.call{value: withdrawAmount}("");
        require(success, "ETH transfer failed");

        emit Withdrawn(msg.sender, withdrawAmount, _shares);
    }

    /**
     * @notice Emergency withdrawal with penalty
     * @dev Demonstrates multiple nonReentrant functions in same contract
     */
    function emergencyWithdraw() public nonReentrant {
        uint256 userShares = shares[msg.sender];
        require(userShares > 0, "No shares to withdraw");

        // Calculate amount with 10% penalty
        uint256 amount = (userShares * totalDeposits) / totalShares;
        uint256 penalty = amount / 10;
        uint256 withdrawAmount = amount - penalty;

        // Effects
        shares[msg.sender] = 0;
        deposits[msg.sender] = 0;
        totalShares -= userShares;
        totalDeposits -= amount;

        // Interactions
        (bool success, ) = msg.sender.call{value: withdrawAmount}("");
        require(success, "ETH transfer failed");

        emit Withdrawn(msg.sender, withdrawAmount, userShares);
    }

    /**
     * @notice Complex function with multiple external calls
     * @dev nonReentrant protects entire function execution
     */
    function claimRewardsAndCompound() public nonReentrant {
        uint256 userShares = shares[msg.sender];
        require(userShares > 0, "No shares");

        // Calculate rewards (simplified for example)
        uint256 rewards = calculateRewards(msg.sender);
        require(rewards > 0, "No rewards");

        // Effects - Update state
        uint256 newShares = (rewards * totalShares) / totalDeposits;
        shares[msg.sender] += newShares;
        totalShares += newShares;
        totalDeposits += rewards;

        // Interactions - Multiple external calls protected by single nonReentrant
        _claimFromExternalProtocol();
        _notifyRewardsClaimed(msg.sender, rewards);

        emit RewardsClaimed(msg.sender, rewards);
    }

    function calculateRewards(address _user) public view returns (uint256) {
        // Simplified rewards calculation
        return (shares[_user] * 5) / 100;
    }

    function _claimFromExternalProtocol() private {
        // External protocol interaction
    }

    function _notifyRewardsClaimed(address _user, uint256 _amount) private {
        // External notification
    }
}

/**
 * @title CrossContractProtection
 * @notice Demonstrates protection against cross-contract reentrancy
 */
contract CrossContractProtection is ReentrancyGuard {
    mapping(address => uint256) public balances;

    // Both functions share the same reentrancy lock
    function functionA() public nonReentrant {
        balances[msg.sender] -= 100;
        // External call cannot reenter functionA OR functionB
        (bool success, ) = msg.sender.call("");
        require(success);
    }

    function functionB() public nonReentrant {
        balances[msg.sender] += 50;
        // Protected from reentrancy even if functionA calls external contract
        (bool success, ) = msg.sender.call("");
        require(success);
    }
}

/**
 * @title CustomReentrancyGuard
 * @notice Custom implementation showing how ReentrancyGuard works internally
 * @dev For educational purposes - use OpenZeppelin in production
 */
contract CustomReentrancyGuard {
    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED = 2;
    uint256 private _status;

    constructor() {
        _status = _NOT_ENTERED;
    }

    modifier nonReentrant() {
        require(_status != _ENTERED, "ReentrancyGuard: reentrant call");
        _status = _ENTERED;
        _;
        _status = _NOT_ENTERED;
    }

    function protectedFunction() public nonReentrant {
        // Function logic here
        // Any reentrant call will fail at the require check
    }
}

// VULNERABLE: Push Payment Pattern (Reentrancy Risk)
contract VulnerablePushPayment {
    address[] public recipients;
    mapping(address => uint256) public shares;

    /**
     * @dev VULNERABLE: Iterates and sends payments in loop
     * Reentrancy risk during each payment, DOS risk if one recipient reverts
     */
    function distributePayments() public {
        for (uint256 i = 0; i < recipients.length; i++) {
            address recipient = recipients[i];
            uint256 amount = shares[recipient];

            // DANGEROUS: State update after external call
            (bool success, ) = recipient.call{value: amount}("");
            require(success, "Payment failed");
            shares[recipient] = 0;  // Too late!
        }
    }
}

// SECURE: Pull Payment Pattern
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title PullPaymentVault
 * @notice Secure payment distribution using pull pattern
 * @dev Users withdraw their own funds instead of receiving pushes
 */
contract PullPaymentVault is ReentrancyGuard {
    mapping(address => uint256) public pendingWithdrawals;
    uint256 public totalPending;

    event PaymentDeposited(address indexed recipient, uint256 amount);
    event PaymentWithdrawn(address indexed recipient, uint256 amount);

    /**
     * @notice Credit payments to recipients (safe, no external calls)
     * @param _recipients Array of addresses to receive payments
     * @param _amounts Corresponding payment amounts
     */
    function creditPayments(
        address[] calldata _recipients,
        uint256[] calldata _amounts
    ) external payable {
        require(_recipients.length == _amounts.length, "Length mismatch");

        uint256 totalAmount = 0;
        for (uint256 i = 0; i < _recipients.length; i++) {
            require(_recipients[i] != address(0), "Invalid recipient");
            require(_amounts[i] > 0, "Invalid amount");

            // Safe: Only updating state, no external calls
            pendingWithdrawals[_recipients[i]] += _amounts[i];
            totalAmount += _amounts[i];

            emit PaymentDeposited(_recipients[i], _amounts[i]);
        }

        require(msg.value >= totalAmount, "Insufficient payment");
        totalPending += totalAmount;

        // Refund excess
        if (msg.value > totalAmount) {
            (bool success, ) = msg.sender.call{value: msg.value - totalAmount}("");
            require(success, "Refund failed");
        }
    }

    /**
     * @notice Recipients withdraw their own payments
     * @dev Protected by nonReentrant and Checks-Effects-Interactions
     */
    function withdraw() public nonReentrant {
        uint256 amount = pendingWithdrawals[msg.sender];
        require(amount > 0, "No pending payments");

        // Effects: Update state BEFORE external call
        pendingWithdrawals[msg.sender] = 0;
        totalPending -= amount;

        // Interactions: Transfer last
        (bool success, ) = msg.sender.call{value: amount}("");
        require(success, "Transfer failed");

        emit PaymentWithdrawn(msg.sender, amount);
    }

    /**
     * @notice Check pending payment without state change
     */
    function getPendingPayment(address _user) public view returns (uint256) {
        return pendingWithdrawals[_user];
    }
}

/**
 * @title DividendDistributor
 * @notice Real-world example: Token dividend distribution using pull pattern
 */
contract DividendDistributor is ReentrancyGuard {
    mapping(address => uint256) public shareholderBalances;
    mapping(address => uint256) public dividendCredited;
    mapping(address => uint256) public dividendWithdrawn;

    uint256 public totalShares;
    uint256 public totalDividends;
    uint256 public dividendsPerShare;

    uint256 private constant PRECISION = 10**18;

    event DividendsDeposited(uint256 amount, uint256 newDividendsPerShare);
    event DividendWithdrawn(address indexed shareholder, uint256 amount);

    /**
     * @notice Deposit dividends for all shareholders
     * @dev Safe: No iteration, no external calls to untrusted addresses
     */
    function depositDividends() external payable {
        require(msg.value > 0, "No dividends");
        require(totalShares > 0, "No shareholders");

        // Update global dividend rate
        uint256 newDividends = msg.value;
        totalDividends += newDividends;
        dividendsPerShare += (newDividends * PRECISION) / totalShares;

        emit DividendsDeposited(newDividends, dividendsPerShare);
    }

    /**
     * @notice Calculate unclaimed dividends for a shareholder
     */
    function getUnclaimedDividends(address _shareholder) public view returns (uint256) {
        if (shareholderBalances[_shareholder] == 0) {
            return 0;
        }

        uint256 totalEarned = (shareholderBalances[_shareholder] * dividendsPerShare) / PRECISION;
        uint256 alreadyWithdrawn = dividendWithdrawn[_shareholder];

        return totalEarned > alreadyWithdrawn ? totalEarned - alreadyWithdrawn : 0;
    }

    /**
     * @notice Shareholders withdraw their own dividends (pull pattern)
     * @dev Combines pull pattern with ReentrancyGuard and CEI
     */
    function withdrawDividends() public nonReentrant {
        uint256 unclaimed = getUnclaimedDividends(msg.sender);
        require(unclaimed > 0, "No dividends to claim");

        // Effects: Update state before transfer
        dividendWithdrawn[msg.sender] += unclaimed;

        // Interactions: Transfer last
        (bool success, ) = msg.sender.call{value: unclaimed}("");
        require(success, "Dividend transfer failed");

        emit DividendWithdrawn(msg.sender, unclaimed);
    }

    /**
     * @notice Issue shares to shareholder
     * @dev Safe: No external calls
     */
    function issueShares(address _shareholder, uint256 _shares) external {
        require(_shareholder != address(0), "Invalid shareholder");
        require(_shares > 0, "Invalid shares");

        shareholderBalances[_shareholder] += _shares;
        totalShares += _shares;
    }
}

/**
 * @title OpenZeppelinPullPayment
 * @notice Using OpenZeppelin's built-in PullPayment contract
 */
import "@openzeppelin/contracts/security/PullPayment.sol";

contract AuctionHouse is PullPayment {
    mapping(uint256 => address) public highestBidder;
    mapping(uint256 => uint256) public highestBid;

    event BidPlaced(uint256 indexed auctionId, address bidder, uint256 amount);

    /**
     * @notice Place bid on auction
     * @dev Refunds previous bidder using pull pattern via _asyncTransfer
     */
    function bid(uint256 _auctionId) external payable {
        require(msg.value > highestBid[_auctionId], "Bid too low");

        address previousBidder = highestBidder[_auctionId];
        uint256 previousBid = highestBid[_auctionId];

        // Update auction state
        highestBidder[_auctionId] = msg.sender;
        highestBid[_auctionId] = msg.value;

        // Credit previous bidder for withdrawal (pull pattern)
        if (previousBidder != address(0)) {
            _asyncTransfer(previousBidder, previousBid);
        }

        emit BidPlaced(_auctionId, msg.sender, msg.value);
    }

    /**
     * @notice Previous bidders withdraw their refunds
     * @dev Inherited from PullPayment, protected against reentrancy
     */
    // withdrawPayments() is inherited from PullPayment
}

/**
 * @title ComparisonExample
 * @notice Side-by-side comparison of push vs pull patterns
 */
contract PushVsPullComparison {
    // PUSH PATTERN: Vulnerable
    function pushPayment(address _recipient, uint256 _amount) external {
        // Problem: External call during critical operation
        (bool success, ) = _recipient.call{value: _amount}("");
        require(success);
        // Reentrancy window exists during this call
    }

    // PULL PATTERN: Safe
    mapping(address => uint256) public credits;

    function creditPayment(address _recipient, uint256 _amount) external {
        // Safe: Only update state, no external calls
        credits[_recipient] += _amount;
    }

    function pullPayment() external {
        uint256 amount = credits[msg.sender];
        require(amount > 0, "No credits");

        // CEI Pattern: Update before transfer
        credits[msg.sender] = 0;

        (bool success, ) = msg.sender.call{value: amount}("");
        require(success);
    }
}

