// Certora specification for reentrancy protection

methods {
    withdraw(uint256) envfree
    balances(address) returns uint256 envfree
}

// Rule: Balance should decrease by exactly withdrawal amount
rule noReentrancy(uint256 amount) {
    env e;
    address user = e.msg.sender;

    uint256 balanceBefore = balances(user);

    withdraw(e, amount);

    uint256 balanceAfter = balances(user);

    // Balance should decrease by exactly the withdrawn amount
    assert balanceBefore - balanceAfter == amount;
}

// Rule: Single call should not allow multiple withdrawals
rule singleWithdrawalPerCall(uint256 amount) {
    env e;

    storage initial = lastStorage;

    withdraw(e, amount);

    // After one withdrawal, trying again should fail or change nothing
    withdraw@withrevert(e, amount) at initial;

    assert lastReverted;
}
EOF

