        if (attackCount < 5 && address(victim).balance > 0) {
            attackCount++;
            victim.withdraw(1 ether);
        }
    }
}

contract ReentrancyTest is Test {
    MyVault public vault;
    Attacker public attacker;

    function setUp() public {
        vault = new MyVault();
        attacker = new Attacker(vault);

        // Fund vault
        vm.deal(address(vault), 100 ether);
    }

    function testReentrancyAttackFails() public {
        vm.deal(address(attacker), 10 ether);

        // Attack should fail if contract is protected
        vm.expectRevert("ReentrancyGuard: reentrant call");
        attacker.attack{value: 1 ether}();
    }

    function testFuzz_NoReentrancy(uint256 depositAmount) public {
        vm.assume(depositAmount > 0.1 ether && depositAmount < 10 ether);

        vm.deal(address(this), depositAmount);
        vault.deposit{value: depositAmount}();

        uint256 balanceBefore = address(this).balance;
        vault.withdraw(depositAmount);
        uint256 balanceAfter = address(this).balance;

        // Should receive exactly the withdrawn amount
        assertEq(balanceAfter - balanceBefore, depositAmount);
    }
}
